'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'
import {
    FinancialAccount,
    FinancialAccountInsert,
    FinancialCategory,
    FinancialTransaction,
    FinancialTransactionInsert,
    CreateTransactionDTO,
    CreateAccountDTO,
    FinancialMetrics
} from '@/types/financial'
import { startOfMonth, endOfMonth } from 'date-fns'

// TRANSACTION ACTIONS

export async function getTransactions(
    startDate?: string,
    endDate?: string,
    limit = 50
) {
    const supabase = await createClient()

    let query = supabase
        .from('financial_transactions')
        .select(`
      *,
      account:financial_accounts!financial_transactions_account_id_fkey(id, name, color),
      category:financial_categories!financial_transactions_category_id_fkey(id, name, color, icon),
      contact:crm_contacts!financial_transactions_contact_id_fkey(id, full_name),
      deal:crm_deals!financial_transactions_deal_id_fkey(id, title)
    `)
        .order('transaction_date', { ascending: false })
        .limit(limit)

    if (startDate) query = query.gte('transaction_date', startDate)
    if (endDate) query = query.lte('transaction_date', endDate)

    const { data, error } = await query

    if (error) {
        console.error('Error fetching transactions:', error)
        return []
    }

    return data as FinancialTransaction[]
}

export async function createTransaction(data: CreateTransactionDTO): Promise<FinancialTransaction> {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) throw new Error('Unauthorized')

    // Prepare payload with proper typing
    const payload: FinancialTransactionInsert = {
        user_id: user.id,
        description: data.description,
        amount: data.amount,
        type: data.type,
        transaction_date: data.transaction_date,
        account_id: data.account_id,
        category_id: data.category_id,
        status: data.status || 'pendente',
        payment_method: data.payment_method,
        contact_id: data.contact_id,
        deal_id: data.deal_id,
        notes: data.notes,
        is_recurring: data.is_recurring,
        net_amount: data.amount,
        created_by: user.id,
    }

    const { data: transaction, error } = await supabase
        .from('financial_transactions')
        .insert(payload as never)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath('/financial')
    return transaction as FinancialTransaction
}

// ACCOUNT ACTIONS

export async function getAccounts() {
    const supabase = await createClient()

    const { data, error } = await supabase
        .from('financial_accounts')
        .select('*')
        .eq('is_active', true)
        .order('name')

    if (error) {
        console.error('Error fetching accounts:', error)
        return []
    }

    return data as FinancialAccount[]
}

export async function createAccount(data: CreateAccountDTO): Promise<FinancialAccount> {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) throw new Error('Unauthorized')

    const payload: FinancialAccountInsert = {
        user_id: user.id,
        name: data.name,
        type: data.type,
        initial_balance: data.initial_balance,
        balance: data.initial_balance,
        bank_name: data.bank_name,
        color: data.color,
        is_active: true,
        is_default: false,
        owner_id: user.id
    }

    const { data: account, error } = await supabase
        .from('financial_accounts')
        .insert(payload as never)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath('/financial')
    return account as FinancialAccount
}

// CATEGORY ACTIONS

export async function getCategories() {
    const supabase = await createClient()

    const { data, error } = await supabase
        .from('financial_categories')
        .select('*')
        .order('name')

    if (error) {
        // If table doesn't exist yet or other error
        console.error('Error fetching categories:', error)
        return []
    }

    return data as FinancialCategory[]
}

// METRICS ACTIONS

export async function getFinancialMetrics(): Promise<FinancialMetrics> {
    const supabase = await createClient()

    // This usually requires complex aggregation.
    // For MVP, we can fetch recent data or use a database function if available.
    // Or fetch all transactions of current month and aggregate in JS (careful with scale).

    const today = new Date();
    const start = startOfMonth(today).toISOString();
    const end = endOfMonth(today).toISOString();

    // 1. Total Balance of all accounts
    const { data: accountsData } = await supabase
        .from('financial_accounts')
        .select('balance')
        .eq('is_active', true);

    const accounts = accountsData as Array<{ balance: number }> | null;
    const totalBalance = accounts?.reduce((acc, curr) => acc + (curr.balance || 0), 0) || 0;

    // 2. Month transactions
    const { data: transactionsData } = await supabase
        .from('financial_transactions')
        .select('amount, type, status')
        .gte('transaction_date', start)
        .lte('transaction_date', end)
        .neq('status', 'cancelada'); // Exclude cancelled

    const transactions = transactionsData as Array<{ amount: number; type: string; status: string }> | null;
    let monthRevenue = 0;
    let monthExpenses = 0;

    transactions?.forEach(t => {
        if (t.type === 'entrada') monthRevenue += t.amount;
        else if (t.type === 'saida') monthExpenses += t.amount;
    });

    const monthProfit = monthRevenue - monthExpenses;
    const monthNetProfit = monthProfit; // Minus costs if we had them separate
    const netProfitMargin = monthRevenue > 0 ? (monthNetProfit / monthRevenue) * 100 : 0;

    return {
        totalBalance,
        monthRevenue,
        monthExpenses,
        monthProfit,
        monthTotalCosts: 0, // Need costs table for this
        monthNetProfit,
        netProfitMargin
    }
}
